    deleted_at timestamp without time zone,
    created_by uuid,
    CONSTRAINT chk_status CHECK (((status >= 1) AND (status <= 4))),
    CONSTRAINT chk_tier CHECK (((tier >= 1) AND (tier <= 3)))
);


